import{_ as t,o,c as a,a2 as r}from"./chunks/framework.AV8XgL04.js";const u=JSON.parse('{"title":"ilingo vs. i18next","description":"","frontmatter":{},"headers":[],"relativePath":"guide/comparison.md","filePath":"guide/comparison.md","lastUpdated":1781455248000}'),d={name:"guide/comparison.md"};function n(i,e,s,l,c,g){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="ilingo-vs-i18next" tabindex="-1">ilingo vs. i18next <a class="header-anchor" href="#ilingo-vs-i18next" aria-label="Permalink to &quot;ilingo vs. i18next&quot;">​</a></h1><p><a href="https://www.i18next.com/" target="_blank" rel="noreferrer"><code>i18next</code></a> is the most widely-used i18n library in the JavaScript ecosystem — mature (since 2011), framework-agnostic at its core, and surrounded by a large plugin ecosystem (backends, language detection, ICU, <code>react-i18next</code>, …). It&#39;s an excellent library and the closest functional peer to ilingo.</p><p>This page is an honest side-by-side: where ilingo is the better fit, where i18next is, and how the two map onto each other. No FUD — the numbers are sourced and the tradeoffs are real.</p><blockquote><p><strong>The one-paragraph version.</strong> ilingo is a smaller, faster, ESM/TypeScript-first core with batteries — lazy-loading stores, a file-system backend, locale negotiation — in the box. i18next is a larger, battle-tested ecosystem with a synchronous API, full ICU MessageFormat (via plugin), and first-party React bindings. Pick ilingo for a lean modern stack across Node / edge / browser / Vue; pick i18next for ecosystem depth, React, or full ICU.</p></blockquote><h2 id="what-they-share" tabindex="-1">What they share <a class="header-anchor" href="#what-they-share" aria-label="Permalink to &quot;What they share&quot;">​</a></h2><p>It&#39;s worth clearing this up first, because it&#39;s a common misconception: <strong>modern i18next is not &quot;non-standard&quot; under the hood.</strong> Since v21 it selects plural forms with <a href="https://developer.mozilla.org/docs/Web/JavaScript/Reference/Global_Objects/Intl/PluralRules" target="_blank" rel="noreferrer"><code>Intl.PluralRules</code></a>, and since v21.3 it formats numbers / dates / lists with the <code>Intl.*</code> APIs — exactly like ilingo. So the difference is <strong>not</strong> &quot;Intl-native vs. not&quot;. The real differences are bundle size, architecture, and the shape of the API.</p><h2 id="bundle-size" tabindex="-1">Bundle size <a class="header-anchor" href="#bundle-size" aria-label="Permalink to &quot;Bundle size&quot;">​</a></h2><p>Core packages, no plugins, measured with <a href="https://bundlephobia.com" target="_blank" rel="noreferrer">bundlephobia</a> (minified, then min + gzip):</p><table tabindex="0"><thead><tr><th>Library</th><th style="text-align:right;">Minified</th><th style="text-align:right;">Min + gzip</th><th style="text-align:right;">Runtime deps</th></tr></thead><tbody><tr><td><strong>ilingo</strong> — full barrel</td><td style="text-align:right;">~15.3 kB</td><td style="text-align:right;"><strong>~6.0 kB</strong></td><td style="text-align:right;">2 (<code>pathtrace</code>, <code>smob</code>)</td></tr><tr><td><strong>ilingo</strong> — <code>Ilingo</code> + <code>MemoryStore</code></td><td style="text-align:right;">—</td><td style="text-align:right;"><strong>~3.3 kB</strong>¹</td><td style="text-align:right;">—</td></tr><tr><td>i18next — core</td><td style="text-align:right;">~42.4 kB</td><td style="text-align:right;">~13.2 kB</td><td style="text-align:right;">0</td></tr></tbody></table><p>¹ ilingo&#39;s own CI-enforced budget (brotli) — see <a href="https://github.com/tada5hi/ilingo/blob/master/.size-limit.json" target="_blank" rel="noreferrer"><code>.size-limit.json</code></a> and <a href="./../performance#bundle-size">Performance → Bundle size</a>.</p><p>ilingo&#39;s core is <strong>less than half</strong> i18next&#39;s core, gzipped — and the gap widens in a real app. A typical i18next deployment adds plugins: <code>i18next-http-backend</code> (loading), <code>i18next-browser-languagedetector</code> (negotiation), each shipping more bytes. ilingo&#39;s equivalents — <a href="./stores#loaderstore"><code>LoaderStore</code></a>, <a href="./locales#negotiating-a-locale-from-a-request"><code>negotiateLocale</code> / <code>parseAcceptLanguage</code></a> — are already counted inside that 6 kB. Tree-shaking goes further still: a <code>defineCatalog</code>-only import is ~1.2 kB.</p><p>ilingo declares <code>&quot;sideEffects&quot;: false</code>, so a bundler drops every export you don&#39;t import.</p><h2 id="throughput" tabindex="-1">Throughput <a class="header-anchor" href="#throughput" aria-label="Permalink to &quot;Throughput&quot;">​</a></h2><p>ilingo runs <strong>1.6× – 2.3× faster than i18next</strong> per call across four representative workloads — <em>despite</em> ilingo&#39;s async <code>get()</code> paying a microtask per call. Full table, methodology, and hardware are on the <a href="./../performance">Performance</a> page; the ratios:</p><table tabindex="0"><thead><tr><th>Workload</th><th style="text-align:right;">ilingo / i18next</th></tr></thead><tbody><tr><td>Cache hit, simple string leaf</td><td style="text-align:right;"><strong>2.03×</strong></td></tr><tr><td>Plural lookup (<code>count = 5</code>)</td><td style="text-align:right;"><strong>2.05×</strong></td></tr><tr><td>Cache miss + 3-deep fallback chain</td><td style="text-align:right;"><strong>2.33×</strong></td></tr><tr><td>Template + <code>Intl.NumberFormat</code> modifier</td><td style="text-align:right;"><strong>1.63×</strong></td></tr></tbody></table><p>These are micro-benchmarks — read the <a href="./../performance#caveats">caveats</a>. Per-call speed almost never dominates a real app (render and hydration do); treat it as evidence of a short resolution path, not a reason to switch on its own.</p><h2 id="feature-by-feature" tabindex="-1">Feature by feature <a class="header-anchor" href="#feature-by-feature" aria-label="Permalink to &quot;Feature by feature&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>ilingo</th><th>i18next</th></tr></thead><tbody><tr><td>Maturity</td><td>newer, smaller community</td><td>since 2011, very large community</td></tr><tr><td>Core size (min + gzip)</td><td>~6.0 kB</td><td>~13.2 kB</td></tr><tr><td>Module format</td><td>ESM-only</td><td>ESM + CJS</td></tr><tr><td>TypeScript</td><td>first-party (TS source)</td><td>first-party types</td></tr><tr><td>Plural rules</td><td><code>Intl.PluralRules</code></td><td><code>Intl.PluralRules</code> (v21+)</td></tr><tr><td>Number / date / list format</td><td><code>Intl.*</code>, built-in</td><td><code>Intl.*</code>, built-in (v21.3+)</td></tr><tr><td>Full ICU MessageFormat (<code>select</code>, nested)</td><td>✗ — ICU-lite (plurals + <code>{{var, formatter}}</code>)</td><td>✓ via <code>i18next-icu</code></td></tr><tr><td>Fallback chain</td><td>BCP-47 walk, built-in</td><td><code>fallbackLng</code>, built-in</td></tr><tr><td>Pluggable storage</td><td><code>IStore</code> port — memory / fs / lazy loader / custom</td><td>plugin backends</td></tr><tr><td>Lazy / code-split loading</td><td><code>LoaderStore</code>, in-core</td><td><code>i18next-http-backend</code> (plugin)</td></tr><tr><td>File-system backend</td><td><code>@ilingo/fs</code>, in-core</td><td><code>i18next-fs-backend</code> (plugin)</td></tr><tr><td>Locale negotiation</td><td><code>negotiateLocale</code> / <code>parseAcceptLanguage</code>, in-core</td><td><code>i18next-browser-languagedetector</code> (plugin)</td></tr><tr><td>Translate call</td><td><strong>async</strong> — <code>get()</code> returns a <code>Promise</code></td><td><strong>sync</strong> — <code>t()</code> returns a string</td></tr><tr><td>Vue</td><td><code>@ilingo/vue</code> (first-party)</td><td><code>i18next-vue</code> (official)</td></tr><tr><td>React</td><td>— (framework-agnostic core is usable)</td><td><code>react-i18next</code> (first-party)</td></tr><tr><td>Plugin ecosystem</td><td>small, young</td><td>large, mature</td></tr></tbody></table><p>Two rows are the actual decision points — far more than bundle bytes:</p><ul><li><strong>Sync vs. async.</strong> i18next&#39;s <code>t()</code> is synchronous: call it in render, get a string back. ilingo&#39;s <code>get()</code> returns a <code>Promise</code>. That async surface is precisely what lets <em>any</em> store be lazy- or network-backed without an API break — it&#39;s what powers <a href="./stores#loaderstore"><code>LoaderStore</code></a> and <code>FSStore</code>. The cost is friction if you want a bare synchronous translate in a hot path. In Vue it&#39;s a non-issue: <a href="./../integrations/vue"><code>@ilingo/vue</code></a>&#39;s <code>useTranslation</code> hides the await behind a reactive <code>Ref</code>.</li><li><strong>ICU MessageFormat.</strong> i18next + <a href="https://github.com/i18next/i18next-icu" target="_blank" rel="noreferrer"><code>i18next-icu</code></a> supports the full ICU grammar (<code>select</code>, nested plurals, ordinals). ilingo is <em>ICU-lite</em>: CLDR plural categories via <a href="./pluralization"><code>definePlural</code></a> plus <code>Intl</code> formatters via <a href="./formatters"><code>{{value, number(...)}}</code></a> — but <strong>no</strong> <code>select</code> / nested message grammar. If your translators rely on full ICU, stay on i18next.</li></ul><h2 id="concept-mapping" tabindex="-1">Concept mapping <a class="header-anchor" href="#concept-mapping" aria-label="Permalink to &quot;Concept mapping&quot;">​</a></h2><p>Porting a mental model — or a codebase — from i18next:</p><table tabindex="0"><thead><tr><th>i18next</th><th>ilingo</th></tr></thead><tbody><tr><td><code>t(&#39;common:greeting&#39;)</code></td><td><code>get({ namespace: &#39;common&#39;, key: &#39;greeting&#39; })</code></td></tr><tr><td><code>t(&#39;key&#39;, { name })</code></td><td><code>{{name}}</code> in the message + <code>data: { name }</code></td></tr><tr><td><code>key_one</code> / <code>key_other</code> suffixes</td><td><code>definePlural({ one, other })</code></td></tr><tr><td>namespaces (<code>ns</code>)</td><td><code>namespace</code> argument / <code>defineNamespace</code></td></tr><tr><td><code>fallbackLng: [&#39;de&#39;, &#39;en&#39;]</code></td><td><code>fallback</code> option (BCP-47 chain)</td></tr><tr><td><code>i18next-http-backend</code></td><td><code>LoaderStore</code> (<code>loader: (l, ns) =&gt; import(...)</code>)</td></tr><tr><td><code>i18next-fs-backend</code></td><td><code>@ilingo/fs</code> <code>FSStore</code></td></tr><tr><td><code>i18next-browser-languagedetector</code></td><td><code>negotiateLocale(supported, navigator.languages)</code></td></tr><tr><td><code>addResourceBundle(...)</code></td><td><code>registerStore(new MemoryStore(...))</code></td></tr></tbody></table><p>See <a href="./catalog-design">Catalog Design</a>, <a href="./stores">Stores</a>, and <a href="./locales">Locales &amp; Fallback</a> for the details.</p><h2 id="when-not-to-choose-ilingo" tabindex="-1">When <strong>not</strong> to choose ilingo <a class="header-anchor" href="#when-not-to-choose-ilingo" aria-label="Permalink to &quot;When **not** to choose ilingo&quot;">​</a></h2><p>Honest disqualifiers — reach for i18next (or <a href="https://formatjs.io/" target="_blank" rel="noreferrer">FormatJS</a>) instead if:</p><ul><li>You have a <strong>large existing i18next codebase.</strong> The migration cost rarely pays back; both are good libraries.</li><li>You need <strong>full ICU MessageFormat</strong> (<code>select</code>, gender, nested plurals) — use <code>i18next-icu</code> or FormatJS.</li><li>You&#39;re <strong>React-first</strong> and want the most-used, best-documented bindings — <code>react-i18next</code> has no ilingo equivalent today.</li><li>You depend on a specific <strong>i18next plugin</strong> (e.g. a <a href="https://locize.com/" target="_blank" rel="noreferrer">locize</a> workflow or a particular backend connector) with no ilingo store yet.</li><li>You want a <strong>fully synchronous</strong> translate function with no async surface anywhere in your stack.</li></ul><p>If none of those apply — and a small bundle and a framework-agnostic, modern core matter to you — ilingo is built for exactly that. Start with the <a href="./../getting-started/quick-start">Quick Start</a>.</p>',28)])])}const p=t(d,[["render",n]]);export{u as __pageData,p as default};
